let data_name: string;
if(title){
  data_name = title
}else if(assetname != "diagram.svg"){
  data_name = assetname
}else if(hash){
  data_name = hash
}else{
  data_name = "diagram.svg"
}

console.log(` * panzoom : '${data_name}' : '${src}'`)
const isSvg = asseturl.endsWith(".svg")
const isImg = !isSvg

