interface Props {
	websiteId: string;
	scriptUrl?: string;
	replaysScriptUrl?: string;
	trackOutboundLinks?: boolean;
	collectWebVitals?: boolean;
	replays?: {
		enabled?: boolean;
		sampleRate?: number;
		maskLevel?: "moderate" | "strict";
		maxDuration?: number;
		blockSelector?: string;
	};
}

const {
	websiteId,
	scriptUrl,
	replaysScriptUrl,
	trackOutboundLinks = true,
	collectWebVitals = false,
	replays,
} = Astro.props;

const replaysEnabled = replays?.enabled ?? false;
const replaysSampleRate = replays?.sampleRate ?? 0.15;
const replaysMaskLevel = replays?.maskLevel ?? "moderate";
const replaysMaxDuration = replays?.maxDuration ?? 300000;
const replaysBlockSelector = replays?.blockSelector?.trim();
---

<script
	is:inline
	data-swup-ignore-script
	defer
	src={scriptUrl}
	data-website-id={websiteId}
	data-performance={collectWebVitals ? "true" : undefined}
></script>

{
	replaysEnabled && (
		<script
			is:inline
			data-swup-ignore-script
			defer
			src={replaysScriptUrl}
			data-website-id={websiteId}
			data-sample-rate={String(replaysSampleRate)}
			data-mask-level={replaysMaskLevel}
			data-max-duration={String(replaysMaxDuration)}
			data-block-selector={replaysBlockSelector || undefined}
		/>
	)
}

{
	trackOutboundLinks && (
		<script is:inline data-swup-ignore-script>
			;(() => {
				const name = 'outbound-link-click'

				const applyOutboundTracking = () => {
					document.querySelectorAll('a').forEach((a) => {
						if (
							a.host !== window.location.host &&
							!a.getAttribute('data-umami-event')
						) {
							a.setAttribute('data-umami-event', name)
							a.setAttribute('data-umami-event-url', a.href)
						}
					})
				}

				if (document.readyState === 'loading') {
					document.addEventListener('DOMContentLoaded', applyOutboundTracking, {
						once: true,
					})
				} else {
					applyOutboundTracking()
				}

				document.addEventListener('astro:page-load', applyOutboundTracking)
			})()
		</script>
	)
}

import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
import process from 'node:process';
import { dset } from 'dset';

interface ConfigOptions {
	name: string;
}

// Adapted from https://github.com/sindresorhus/env-paths
function getConfigDir(name: string) {
	const homedir = os.homedir();
	const macos = () => path.join(homedir, 'Library', 'Preferences', name);
	const win = () => {
		const { APPDATA = path.join(homedir, 'AppData', 'Roaming') } = process.env;
		return path.join(APPDATA, name, 'Config');
	};
	const linux = () => {
		const { XDG_CONFIG_HOME = path.join(homedir, '.config') } = process.env;
		return path.join(XDG_CONFIG_HOME, name);
	};
	// eslint-disable-next-line @typescript-eslint/switch-exhaustiveness-check
	switch (process.platform) {
		case 'darwin':
			return macos();
		case 'win32':
			return win();
		default:
			return linux();
	}
}

export class GlobalConfig {
	private project: ConfigOptions;
	private dir: string;
	private file: string;

	constructor(project: ConfigOptions) {
		this.project = project;
		this.dir = getConfigDir(this.project.name);
		this.file = path.join(this.dir, 'config.json');
	}

	private _store?: Record<string, any>;
	private get store(): Record<string, any> {
		if (this._store) return this._store;
		this.ensureDir();
		if (fs.existsSync(this.file)) {
			try {
				this._store = JSON.parse(fs.readFileSync(this.file).toString());
			} catch {}
		}
		if (!this._store) {
			this._store = {};
			this.write();
		}
		return this._store;
	}
	private set store(value: Record<string, any>) {
		this._store = value;
		this.write();
	}
	private ensureDir() {
		fs.mkdirSync(this.dir, { recursive: true });
	}
	write() {
		fs.writeFileSync(this.file, JSON.stringify(this.store, null, '\t'));
	}
	clear(): void {
		this.store = {};
		fs.rmSync(this.file, { recursive: true });
	}
	delete(key: string): boolean {
		dset(this.store, key, undefined);
		this.write();
		return true;
	}
	get(key: string): any {
		return key.split('.').reduce((obj, k) => obj?.[k], this.store);
	}
	has(key: string): boolean {
		return typeof this.get(key) !== 'undefined';
	}
	set(key: string, value: any): void {
		dset(this.store, key, value);
		this.write();
	}
}

import * as bootstrap from 'bootstrap/dist/js/bootstrap.esm.js'
import SimpleBar from 'simplebar'
import { darkMode } from './layout/dark-mode.js'
import { initSidebar } from './layout/sidebar-handler.js'
import { initSidebarMini } from './layout/sidebar-mini-handler.js'
import { initNavigation } from './layout/nav-handler.js'
import { initPasswordWrapper } from './components/password.js'
import { initSkin, updateSkin } from './components/skin.js'

// Expose bootstrap and simplebar globally for inline scripts
window.bootstrap = bootstrap
window.SimpleBar = SimpleBar

// Create the theme module
const AsteroAdmin = (function () {
  let initialized = false

  // Initialize Bootstrap components
  function initBootstrap() {
    // Enable tooltips everywhere
    const tooltipTriggerList = document.querySelectorAll('[data-bs-toggle="tooltip"]')
    Array.from(tooltipTriggerList).forEach((tooltipTriggerEl) => {
      new bootstrap.Tooltip(tooltipTriggerEl)
    })

    // Enable popovers everywhere
    const popoverTriggerList = document.querySelectorAll('[data-bs-toggle="popover"]')
    Array.from(popoverTriggerList).forEach((popoverTriggerEl) => {
      new bootstrap.Popover(popoverTriggerEl)
    })
  }

  // Initialize SimpleBar on elements with data-simplebar attribute
  function initSimpleBar() {
    document.querySelectorAll('[data-simplebar]').forEach((element) => {
      new SimpleBar(element)
    })
  }

  function initializeAll() {
    if (initialized) {
      return
    }

    try {
      darkMode()
      initSidebar()
      initSidebarMini()
      initNavigation()
      initPasswordWrapper()
      initBootstrap()
      initSimpleBar()

      // Initialize skin system
      initSkin()

      initialized = true
    } catch (error) {
      console.error('Error during initialization:', error)
    }
  }

  // Public API
  return {
    init: initializeAll,
    isInitialized: () => initialized,
    updateSkin: updateSkin
  }
})()

// Auto-initialize when DOM is ready
if (typeof document !== 'undefined') {
